BEGIN TRANSACTION;
CREATE TABLE courses (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT
    );
CREATE TABLE quiz_results (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    user_id INTEGER,
    course_id INTEGER,
    score INTEGER,
    passed INTEGER
);
CREATE TABLE quizzes (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    course_id INTEGER,
    question TEXT,
    option1 TEXT,
    option2 TEXT,
    option3 TEXT,
    option4 TEXT,
    correct_answer TEXT
);
print(type(3.14))','int','float','str','bool','float');
print(''Python''[1])','P','y','t','h','y');
print(10 / 3)','3','3.333','3.0','3.3333','3.3333333333333335');
print(len([1, 2, 3, 4]))','3','4','5','6','4');
print(2 ** 3)','6','8','9','16','8');
print(''Hello, World!''.split('',''))','[''Hello'', '' World!'']','[''Hello, World!'']','[''Hello'', ''World!'']','Hello, World!','[''Hello'', '' World!'']');
print(10 % 3)','1','3','0','2','1');
print(''Python''.upper())','python','PYTHON','pYTHON','Python','PYTHON');
print(True and False)','True','False','None','Error','False');
print([1, 2, 3] + [4, 5, 6])','[1, 2, 3, 4, 5, 6]','[5, 7, 9]','[1, 2, 3][4, 5, 6]','Error','[1, 2, 3, 4, 5, 6]');
print(''Python''[::-1])','Python','nohtyP','Ptoh','nothyp','nohtyP');
print(len(''Python''))','5','6','7','8','6');
print(''Python'' * 2)','PythonPython','Python2','Error','Python Python','PythonPython');
print(10 // 3)','3','3.333','3.0','3.3333','3');
print(''Python''.find(''th''))','1','2','3','4','2');
print(''Python''[2:4])','th','yt','to','hn','th');
print(''Python''.islower())','True','False','None','Error','False');
print(''Python''.replace(''th'', ''zz''))','Pzzon','Pyzzon','Python','Error','Pyzzon');
print(''Python'' in ''I love Python'')','True','False','None','Error','True');
print(''Python''[-2])','o','n','h','y','o');
print(''Python''[0])','P','y','t','h','P');
print(''Python''.startswith(''Py''))','True','False','None','Error','True');
CREATE TABLE results (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        student_id INTEGER,
        course_id INTEGER,
        score INTEGER,
        total INTEGER,
        status TEXT
    );
DELETE FROM "sqlite_sequence";
